// Prepare meeting booking context
const input = $input.first().json;

// Determine source (webhook or scheduled)
let prospect;
let source;

if (input.fields) {
  // From Airtable (scheduled)
  prospect = input;
  source = 'scheduled';
} else {
  // From webhook
  prospect = input;
  source = 'webhook';
}

const companyName = prospect.fields?.['Company Name'] || prospect.companyName || 'Unknown';
const email = prospect.fields?.['Verified Email'] || prospect.email || '';
const phone = prospect.fields?.['Phone'] || prospect.phone || '';
const contactName = prospect.fields?.['Contact Name'] || prospect.contactName || '';

return {
  json: {
    prospectId: prospect.id || prospect.prospectId,
    companyName: companyName,
    email: email,
    phone: phone,
    contactName: contactName,
    source: source
  }
};

// Generate available time slots
const busyTimes = $input.first().json.calendars?.primary?.busy || [];
const context = $('Prepare Context').first().json;

// Business hours: 9 AM - 5 PM, Mon-Fri
const slots = [];
const now = new Date();

for (let day = 1; day <= 7; day++) {
  const date = new Date(now);
  date.setDate(date.getDate() + day);

  // Skip weekends
  if (date.getDay() === 0 || date.getDay() === 6) continue;

  // Generate slots for this day
  for (let hour = 9; hour <= 16; hour++) {
    const slotStart = new Date(date);
    slotStart.setHours(hour, 0, 0, 0);

    const slotEnd = new Date(slotStart);
    slotEnd.setMinutes(30);

    // Check if slot conflicts with busy times
    const isAvailable = !busyTimes.some(busy => {
      const busyStart = new Date(busy.start);
      const busyEnd = new Date(busy.end);
      return slotStart < busyEnd && slotEnd > busyStart;
    });

    if (isAvailable) {
      slots.push({
        start: slotStart.toISOString(),
        end: slotEnd.toISOString(),
        display: slotStart.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' }) + 
                 ' at ' + slotStart.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' })
      });
    }
  }
}

// Take first 6 available slots
const availableSlots = slots.slice(0, 6);

return {
  json: {
    ...context,
    availableSlots: availableSlots,
    slotsText: availableSlots.map((s, i) => `${i + 1}. ${s.display}`).join('\n')
  }
};

