const response = $input.first().json.message?.content || $input.first().json.text || '{}';
let email;

try {
  email = JSON.parse(response);
} catch (e) {
  const match = response.match(/\{[\s\S]*\}/);
  email = match ? JSON.parse(match[0]) : { subject: 'Quick call this week?', body: response };
}

const context = $('Generate Available Slots').first().json;

return {
  json: {
    ...context,
    emailSubject: email.subject,
    emailBody: email.body
  }
};

// Process Calendly booking
const event = $input.first().json;

const inviteeEmail = event.payload?.invitee?.email || event.invitee_email || '';
const inviteeName = event.payload?.invitee?.name || event.invitee_name || '';
const eventTime = event.payload?.event?.start_time || event.event_start_time || '';
const eventName = event.payload?.event?.name || event.event_name || 'Discovery Call';

return {
  json: {
    inviteeEmail: inviteeEmail.toLowerCase(),
    inviteeName: inviteeName,
    meetingTime: eventTime,
    meetingName: eventName,
    bookedAt: new Date().toISOString()
  }
};

